from ldap3 import Server, Connection, ALL, NTLM_AUTH

def search_user(username):
    server = Server('ldap.example.com', get_info=ALL)
    connection = Connection(server, user='bind_dn', password='bind_password', authentication=NTLM_Auth)
    connection.open()

    base_dn = 'dc=example,dc=com'
    search_filter = f'(&(objectClass=user)(uid={username}))'

    results = connection.search(base_dn, search_filter, attributes=['uid', 'cn', 'sn'])

    for result in results:
        print(f"UID: {result['uid'][0]}, CN: {result['cn'][0]}, SN: {result['sn'][0]}")

    connection.close()